import { NewsPartials } from '@/partials'

export default {
  components: {
    NewsPartials
  },
  data () {
    return {
      id: this.$route.params.id,
      title: null,
      body: null
    }
  },
  mounted () {
    fetch('https://jsonplaceholder.typicode.com/posts/' + this.id)
      .then(response => response.json())
      .then(json => {
        this.title = json.title
        this.body = json.body
        console.log(json)
      })
  }
}
