import { EventsPartials } from '@/partials'
import Vue from 'vue'

export default {
  components: {
    EventsPartials
  },
  data () {
    return {
      events: []
    }
  },
  mounted () {
    fetch('https://jsonplaceholder.typicode.com/posts/')
      .then(response => response.json())
      .then(json => {
        json.forEach((element, i) => {
          if (i < 5) {
            Vue.set(this.events, i, element)
            this.events[i] = element
          }
        })
        console.log(this.events)
      })
  }
}
