/* eslint-disable no-undef */
/* eslint-disable no-unused-vars */
var quiz = {
  title: 'Тест',
  questions: [
    {
      text: '1 Сколько выводов отладочной платы Arduino Nano можно использовать в качестве цифровых выходов? Это вопрос для знатоков. Если вы будете не согласны с ошибочностью вашего ответа, попробуйте изучить этот вопрос подробнее.',
      weight: 1,
      responses: [
        { text: '14' },
        { text: '8' },
        { text: '22' },
        { text: '20', correct: true }
      ]
    },
    {
      text: '2 На какой максимальной частоте может работать микроконтроллер согласно документации производителя?',
      weight: 1,
      responses: [
        { text: '1 МГц' },
        { text: '8 МГц' },
        { text: '16 МГц' },
        { text: '20 МГц', correct: true }
      ]
    },
    {
      text: '3 Как будет гореть светодиод, подключенный анодом к выводу микроконтроллера (катод через токоограничивающий резистор подключен к GND) с коэффициентом заполнения ШИМ 50%?',
      weight: 2,
      responses: [
        { text: 'Будет мигать с периодом 1 с (0,5 с горит, потом 0,5 с не горит)' },
        { text: 'Не будет гореть. Для работы светодиод нужно подключить катодом к выводу микроконтроллера.' },
        { text: 'Не будет гореть. Коэффициент заполнения слишком мал.' },
        { text: 'Будет гореть достаточно ярко. Интенсивность свечения почти не отличается от случая подключения к выводу с постоянно высоким логическим уровнем.', correct: true }
      ]
    },
    {
      text: 'Некоторый микроконтроллер имеет 4-битный аналого-цифровой преобразователь. Максимальное напряжение а входе АЦП равно 4 В. Какое минимальное изменение напряжения можно зарегистрировать на входе такого АЦП?',
      weight: 1,
      responses: [
        { text: '1000 мВ' },
        { text: '500 мВ' },
        { text: '400 мВ' },
        { text: '250 мВ', correct: true }
      ]
    },
    {
      text: 'Рассчитайте номинал токоограничивающего резистора для светодиода с падением напряжения 2,5 В и номинальным током 25 мА, подключенного к линии питания 5 В.',
      weight: 1,
      responses: [
        { text: '220 Ом' },
        { text: '1 кОм' },
        { text: '250 Ом' },
        { text: '100 Ом', correct: true }
      ]
    }
  ]
}

export default {
  data () {
    return {
      quiz: quiz,
      questionIndex: 0,
      userResponses: Array(quiz.questions.length).fill(false)
    }
  },
  methods: {
    next: function () {
      this.questionIndex++
    },
    prev: function () {
      this.questionIndex--
    },
    score: function () {
      return this.userResponses.reduce((acc, cur, index) => {
        const correctIndex = this.quiz.questions[index].responses.findIndex(r => r.correct)
        return cur === correctIndex
          ? acc + 1
          : acc
      }, 0)
    }
  },
  computed: {
    weight: function () {
      const totalWeigth = this.quiz.questions.reduce((acc, cur) => {
        return acc + cur.weight
      }, 0)

      const correctWeigth = this.userResponses.reduce((acc, cur, index) => {
        const correctIndex = this.quiz.questions[index].responses.findIndex(r => r.correct)
        return cur === correctIndex
          ? acc + this.quiz.questions[index].weight
          : acc
      }, 0)

      return Math.round((correctWeigth / totalWeigth) * 100, 1)
    }
  }
}
