import { Drag, Drop } from 'vue-drag-drop'
import { PartialsDronComponent } from '@/components'
import initialCopter from '@/copter.json'

export default {
  components: {
    PartialsDronComponent, Drag, Drop
  },
  data () {
    return {
      copters: initialCopter.map(c => ({ ...c, installed: false })),
      partToInstall: null,
      wrongPartMessage: null
    }
  },
  computed: {
    assembled () {
      return !this.copters.find(c => c.installed === false)
    }
  },
  mounted () {
    console.log('this', this)
    this.partToInstall = this.getPartToInstall()
  },
  methods: {
    handleDrop (copterId) {
      console.log('copterId', copterId)
      const copter = this.copters.find(c => c.id === copterId)
      if (copterId !== this.partToInstall.id) {
        this.wrongPartMessage = `Это деталь '${copter.name}', а не '${this.partToInstall.name}'`
      } else {
        copter.installed = true
        this.wrongPartMessage = null
        this.partToInstall = this.getPartToInstall()
      }
    },
    getPartToInstall () {
      const notInstalledParts = this.copters.filter(c => !c.installed)
      return notInstalledParts.length
        ? notInstalledParts[Math.floor(Math.random() * (notInstalledParts.length - 1))]
        : null
    }
  }
}
