import Vue from 'vue'
import Router from 'vue-router'
import { MainPage, SensorsPage, LegalLawPage, OurEventsPage, NewsPage, FaqPage, ContactsPage, TestPage } from '@/pages'

Vue.use(Router)

export default new Router({
  mode: 'history',
  base: process.env.BASE_URL,

  routes: [
    {
      path: '/',
      name: 'main',
      component: MainPage
    },
    {
      path: '/sensors',
      name: 'sensors',
      component: SensorsPage
    },
    {
      path: '/legallaw',
      name: 'legallaw',
      component: LegalLawPage
    },
    {
      path: '/ourevents',
      name: 'ourevents',
      component: OurEventsPage
    },
    {
      path: '/faq',
      name: 'faq',
      component: FaqPage
    },
    {
      path: '/contact',
      name: 'contact',
      component: ContactsPage
    },
    {
      path: '/test',
      name: 'test',
      component: TestPage
    },
    { path: '/posts/:id', component: NewsPage }
  ]
})
